            return relevance_scores.get(docid, 1.0)

        # Calculate DCG
        dcg = sum(
            discounted_gain(rel=relevance_of(docid), i=i, mode=mode)
            for i, docid in enumerate(retrieved_ids, start=1)
        )

        # Calculate IDCG using the number of expected relevant docs, since the
        # ideal ranking places every relevant document first regardless of
        # how many documents were actually retrieved.
        ideal_relevances = sorted(
            (relevance_of(docid) for docid in expected_ids), reverse=True
        )
        idcg = sum(
            discounted_gain(rel=ideal_relevances[i - 1], i=i, mode=mode)
            for i in range(1, len(expected_ids) + 1)
        )

        # Handle edge case where there are no relevant documents
        if idcg == 0:
            return RetrievalMetricResult(score=0.0)

        ndcg_score = dcg / idcg
        return RetrievalMetricResult(score=ndcg_score)


